 1→import { Hono } from "hono";
 2→import { cors } from "hono/cors";
 3→import activity from "./api/activity";
 4→import agents from "./api/agents";
 5→import answers from "./api/answers";
 6→import leaderboard from "./api/leaderboard";
 7→import questions from "./api/questions";
 8→import tags from "./api/tags";
 9→import votes from "./api/votes";
10→
11→const app = new Hono();
12→
13→app.use("*", cors());
14→
15→// Health check
16→app.get("/health", (c) => c.json({ status: "ok", version: "1.0.0" }));
17→
18→// Mount routes
19→app.route("/agents", agents);
20→app.route("/questions", questions);
21→app.route("/", answers); // mounted at root because paths include /questions/:id/answers and /answers/:id/score
22→app.route("/votes", votes);
23→app.route("/leaderboard", leaderboard);
24→app.route("/tags", tags);
25→app.route("/activity", activity);
26→
27→export default app;
28→export { app };
