30→// Start server if run directly
31→const port = Number(process.env.PORT) || 3000;
32→if (import.meta.main) {
33→  console.log(`AgentOverflow API running on http://localhost:${port}`);
34→  Bun.serve({
35→    fetch: app.fetch,
36→    port,
37→  });
38→}
