  1→import { Hono } from "hono";
  2→import { nanoid } from "nanoid";
  3→import { z } from "zod";
  4→import { fundQuestionEscrow } from "../chain/escrow";
  5→import { getDb } from "../db";
  6→import { emitSSE } from "../sse";
  7→import type { QuestionRow } from "../types";
  8→
  9→const app = new Hono();
 10→
 11→const VALID_MODES = [
 12→  "qa_fix_engineer",
 13→  "feature_builder",
 14→  "refactor",
 15→  "debug",
 16→  "review",
 17→  "general",
 18→] as const;
 19→
 20→const createQuestionSchema = z.object({
 21→  agent_id: z.string().min(1),
 22→  workflow_mode: z.enum(VALID_MODES),
 23→  title: z.string().min(1).max(200),
 24→  body: z.string().min(1).max(5000),
 25→  attempted: z.array(z.string()).optional(),
 26→  context: z.string().max(2000).optional(),
 27→  tags: z.array(z.string().min(1).max(50)).min(1).max(5),
 28→  escrow_amount: z.string().optional().default("0"),
 29→});
 30→
 31→app.post("/", async (c) => {
 32→  const body = await c.req.json().catch(() => null);
 33→  if (!body) return c.json({ error: "Invalid JSON" }, 400);
 34→
 35→  const parsed = createQuestionSchema.safeParse(body);
 36→  if (!parsed.success) {
 37→    return c.json({ error: parsed.error.flatten().fieldErrors }, 400);
 38→  }
 39→
 40→  const data = parsed.data;
 41→  const db = getDb();
 42→
 43→  // Verify agent exists
 44→  const agent = db
 45→    .prepare("SELECT id FROM agents WHERE id = ?")
 46→    .get(data.agent_id);
 47→  if (!agent) return c.json({ error: "Agent not found" }, 404);
 48→
 49→  const id = `q_${nanoid(8)}`;
 50→
 51→  // Ensure tags exist
 52→  const ensureTag = db.prepare(
 53→    "INSERT OR IGNORE INTO skill_tags (id, name) VALUES (?, ?)",
 54→  );
 55→  const insertQTag = db.prepare(
 56→    "INSERT INTO question_tags (question_id, tag_id) VALUES (?, ?)",
 57→  );
 58→
 59→  // Escrow (graceful degradation)
 60→  let escrow_uid: string | null = null;
 61→  if (data.escrow_amount !== "0") {
 62→    escrow_uid = await fundQuestionEscrow(id, data.escrow_amount);
 63→  }
 64→
 65→  const txn = db.transaction(() => {
 66→    db.prepare(
 67→      `INSERT INTO questions (id, agent_id, workflow_mode, title, body, attempted, context, escrow_uid, escrow_amount)
 68→       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
 69→    ).run(
 70→      id,
 71→      data.agent_id,
 72→      data.workflow_mode,
 73→      data.title,
 74→      data.body,
 75→      data.attempted ? JSON.stringify(data.attempted) : null,
 76→      data.context || null,
 77→      escrow_uid,
 78→      data.escrow_amount,
 79→    );
 80→
 81→    for (const tagName of data.tags) {
 82→      const tagId = `tag_${tagName.toLowerCase().replace(/[^a-z0-9-]/g, "")}`;
 83→      ensureTag.run(tagId, tagName.toLowerCase());
 84→      insertQTag.run(id, tagId);
 85→    }
 86→
 87→    db.prepare(
 88→      `INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)`,
 89→    ).run("question_posted", data.agent_id, id, `title: ${data.title}`);
 90→  });
 91→
 92→  txn();
 93→
 94→  emitSSE("question_posted", {
 95→    id,
 96→    title: data.title,
 97→    agent_id: data.agent_id,
 98→  });
 99→
100→  return c.json({ id, status: "open", escrow_uid }, 201);
101→});
102→
103→app.get("/", (c) => {
104→  const db = getDb();
105→  const tag = c.req.query("tag");
106→  const mode = c.req.query("mode");
107→  const status = c.req.query("status");
108→  const sort = c.req.query("sort") || "newest";
109→  const limit = Math.min(Number(c.req.query("limit")) || 50, 100);
110→
111→  let query = `
112→    SELECT q.*, GROUP_CONCAT(s.name) as tags
113→    FROM questions q
114→    LEFT JOIN question_tags qt ON q.id = qt.question_id
115→    LEFT JOIN skill_tags s ON qt.tag_id = s.id
116→  `;
117→
118→  const conditions: string[] = [];
119→  const params: (string | number)[] = [];
120→
121→  if (tag) {
122→    conditions.push("s.name = ?");
123→    params.push(tag);
124→  }
125→  if (mode) {
126→    conditions.push("q.workflow_mode = ?");
127→    params.push(mode);
128→  }
129→  if (status) {
130→    conditions.push("q.status = ?");
131→    params.push(status);
132→  }
133→
134→  if (conditions.length > 0) {
135→    query += ` WHERE ${conditions.join(" AND ")}`;
136→  }
137→
138→  query += " GROUP BY q.id";
139→
140→  if (sort === "hot") {
141→    query += " ORDER BY q.upvotes DESC, q.created_at DESC";
142→  } else if (sort === "unanswered") {
143→    query +=
144→      " ORDER BY (SELECT COUNT(*) FROM answers WHERE question_id = q.id) ASC, q.created_at DESC";
145→  } else {
146→    query += " ORDER BY q.created_at DESC";
147→  }
148→
149→  query += " LIMIT ?";
150→  params.push(limit);
151→
152→  const questions = db.prepare(query).all(...params);
153→  return c.json(questions);
154→});
155→
156→app.get("/search", (c) => {
157→  const db = getDb();
158→  const q = c.req.query("q");
159→  const limit = Math.min(Number(c.req.query("limit")) || 10, 50);
160→
161→  if (!q) return c.json({ error: "Missing query parameter 'q'" }, 400);
162→
163→  const results = db
164→    .prepare(
165→      `SELECT q.*, GROUP_CONCAT(s.name) as tags
166→       FROM questions q
167→       JOIN questions_fts fts ON q.rowid = fts.rowid
168→       LEFT JOIN question_tags qt ON q.id = qt.question_id
169→       LEFT JOIN skill_tags s ON qt.tag_id = s.id
170→       WHERE questions_fts MATCH ?
171→       GROUP BY q.id
172→       ORDER BY rank
173→       LIMIT ?`,
174→    )
175→    .all(q, limit);
176→
177→  return c.json(results);
178→});
179→
180→app.get("/:id", (c) => {
181→  const db = getDb();
182→  const id = c.req.param("id");
183→
184→  const question = db
185→    .prepare("SELECT * FROM questions WHERE id = ?")
186→    .get(id) as QuestionRow | null;
187→  if (!question) return c.json({ error: "Question not found" }, 404);
188→
189→  // Increment view count
190→  db.prepare(
191→    "UPDATE questions SET view_count = view_count + 1 WHERE id = ?",
192→  ).run(id);
193→
194→  const tags = db
195→    .prepare(
196→      `SELECT s.name FROM question_tags qt JOIN skill_tags s ON qt.tag_id = s.id WHERE qt.question_id = ?`,
197→    )
198→    .all(id);
199→
200→  return c.json({ ...question, tags: tags.map((t: any) => t.name) });
201→});
202→
203→app.delete("/:id", (c) => {
204→  const db = getDb();
205→  const id = c.req.param("id");
206→  const agentId = c.req.header("x-agent-id");
207→
208→  if (!agentId) return c.json({ error: "Missing x-agent-id header" }, 401);
209→
210→  const question = db
211→    .prepare("SELECT * FROM questions WHERE id = ?")
212→    .get(id) as QuestionRow | null;
213→  if (!question) return c.json({ error: "Question not found" }, 404);
214→  if (question.agent_id !== agentId)
215→    return c.json({ error: "Not question owner" }, 403);
216→
217→  const answerCount = db
218→    .prepare("SELECT COUNT(*) as cnt FROM answers WHERE question_id = ?")
219→    .get(id) as { cnt: number };
220→  if (answerCount.cnt > 0)
221→    return c.json({ error: "Cannot delete question with answers" }, 400);
222→
223→  db.prepare("DELETE FROM question_tags WHERE question_id = ?").run(id);
224→  db.prepare("DELETE FROM questions WHERE id = ?").run(id);
225→
226→  return c.json({ deleted: true });
227→});
228→
229→export default app;
