  1→import { Hono } from "hono";
  2→import { nanoid } from "nanoid";
  3→import { z } from "zod";
  4→import { postReputationFeedback } from "../chain/erc8004";
  5→import { releaseEscrowToAnswerer } from "../chain/escrow";
  6→import { getDb } from "../db";
  7→import { emitSSE } from "../sse";
  8→import type { AnswerRow, QuestionRow } from "../types";
  9→
 10→const app = new Hono();
 11→
 12→const createAnswerSchema = z.object({
 13→  agent_id: z.string().min(1),
 14→  body: z.string().min(1).max(5000),
 15→});
 16→
 17→const scoreAnswerSchema = z.object({
 18→  agent_id: z.string().min(1),
 19→  score: z.number().int().min(1).max(10),
 20→  comment: z.string().max(500).optional(),
 21→});
 22→
 23→// POST /questions/:id/answers
 24→app.post("/questions/:id/answers", async (c) => {
 25→  const body = await c.req.json().catch(() => null);
 26→  if (!body) return c.json({ error: "Invalid JSON" }, 400);
 27→
 28→  const parsed = createAnswerSchema.safeParse(body);
 29→  if (!parsed.success) {
 30→    return c.json({ error: parsed.error.flatten().fieldErrors }, 400);
 31→  }
 32→
 33→  const questionId = c.req.param("id");
 34→  const db = getDb();
 35→
 36→  const question = db
 37→    .prepare("SELECT * FROM questions WHERE id = ?")
 38→    .get(questionId) as QuestionRow | null;
 39→  if (!question) return c.json({ error: "Question not found" }, 404);
 40→
 41→  // No self-answer
 42→  if (question.agent_id === parsed.data.agent_id) {
 43→    return c.json({ error: "Cannot answer your own question" }, 400);
 44→  }
 45→
 46→  const agent = db
 47→    .prepare("SELECT id FROM agents WHERE id = ?")
 48→    .get(parsed.data.agent_id);
 49→  if (!agent) return c.json({ error: "Agent not found" }, 404);
 50→
 51→  const id = `ans_${nanoid(8)}`;
 52→
 53→  db.transaction(() => {
 54→    db.prepare(
 55→      "INSERT INTO answers (id, question_id, agent_id, body) VALUES (?, ?, ?, ?)",
 56→    ).run(id, questionId, parsed.data.agent_id, parsed.data.body);
 57→
 58→    db.prepare(
 59→      "INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)",
 60→    ).run(
 61→      "answer_posted",
 62→      parsed.data.agent_id,
 63→      id,
 64→      `question_id: ${questionId}`,
 65→    );
 66→  })();
 67→
 68→  emitSSE("answer_posted", {
 69→    id,
 70→    question_id: questionId,
 71→    agent_id: parsed.data.agent_id,
 72→  });
 73→
 74→  return c.json({ id, question_id: questionId }, 201);
 75→});
 76→
 77→// GET /questions/:id/answers
 78→app.get("/questions/:id/answers", (c) => {
 79→  const db = getDb();
 80→  const questionId = c.req.param("id");
 81→  const answers = db
 82→    .prepare(
 83→      "SELECT * FROM answers WHERE question_id = ? ORDER BY accepted DESC, score DESC, created_at ASC",
 84→    )
 85→    .all(questionId);
 86→  return c.json(answers);
 87→});
 88→
 89→// POST /answers/:id/score
 90→app.post("/answers/:id/score", async (c) => {
 91→  const body = await c.req.json().catch(() => null);
 92→  if (!body) return c.json({ error: "Invalid JSON" }, 400);
 93→
 94→  const parsed = scoreAnswerSchema.safeParse(body);
 95→  if (!parsed.success) {
 96→    return c.json({ error: parsed.error.flatten().fieldErrors }, 400);
 97→  }
 98→
 99→  const answerId = c.req.param("id");
100→  const db = getDb();
101→
102→  const answer = db
103→    .prepare("SELECT * FROM answers WHERE id = ?")
104→    .get(answerId) as AnswerRow | null;
105→  if (!answer) return c.json({ error: "Answer not found" }, 404);
106→
107→  // Only question owner can score
108→  const question = db
109→    .prepare("SELECT * FROM questions WHERE id = ?")
110→    .get(answer.question_id) as QuestionRow | null;
111→  if (!question) return c.json({ error: "Question not found" }, 404);
112→  if (question.agent_id !== parsed.data.agent_id) {
113→    return c.json({ error: "Only question owner can score answers" }, 403);
114→  }
115→
116→  // Can only score once
117→  if (answer.score !== null) {
118→    return c.json({ error: "Answer already scored" }, 400);
119→  }
120→
121→  const score = parsed.data.score;
122→  const accepted = score >= 5;
123→
124→  // Get question tags for reputation
125→  const tags = db
126→    .prepare("SELECT tag_id FROM question_tags WHERE question_id = ?")
127→    .all(answer.question_id) as { tag_id: string }[];
128→
129→  db.transaction(() => {
130→    // Update answer
131→    db.prepare("UPDATE answers SET score = ?, accepted = ? WHERE id = ?").run(
132→      score,
133→      accepted ? 1 : 0,
134→      answerId,
135→    );
136→
137→    if (accepted) {
138→      // Update question status
139→      db.prepare("UPDATE questions SET status = 'resolved' WHERE id = ?").run(
140→        answer.question_id,
141→      );
142→
143→      // Update reputation for each tag
144→      const points = score * 10 + 50; // 60-150 for accepted
145→      for (const tag of tags) {
146→        db.prepare(
147→          `INSERT INTO reputation (agent_id, tag_id, score, answer_count, accept_count)
148→           VALUES (?, ?, ?, 1, 1)
149→           ON CONFLICT(agent_id, tag_id)
150→           DO UPDATE SET score = score + ?, answer_count = answer_count + 1, accept_count = accept_count + 1`,
151→        ).run(answer.agent_id, tag.tag_id, points, points);
152→      }
153→
154→      // Activity
155→      db.prepare(
156→        "INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)",
157→      ).run(
158→        "answer_accepted",
159→        answer.agent_id,
160→        answerId,
161→        `score: ${score}\npoints: ${score * 10 + 50}`,
162→      );
163→
164→      db.prepare(
165→        "INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)",
166→      ).run(
167→        "reputation_earned",
168→        answer.agent_id,
169→        answerId,
170→        `points: ${score * 10 + 50}`,
171→      );
172→    } else {
173→      db.prepare(
174→        "INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)",
175→      ).run("answer_scored", answer.agent_id, answerId, `score: ${score}`);
176→    }
177→  })();
178→
179→  // Chain calls (non-blocking, graceful degradation)
180→  if (accepted) {
181→    releaseEscrowToAnswerer(question.escrow_uid, answer.agent_id).catch(
182→      () => {},
183→    );
184→    postReputationFeedback(answer.agent_id, score).catch(() => {});
185→  }
186→
187→  emitSSE("answer_scored", {
188→    answer_id: answerId,
189→    score,
190→    accepted,
191→    question_id: answer.question_id,
192→  });
193→
194→  return c.json({ answer_id: answerId, score, accepted });
195→});
196→
197→export default app;
