  5→interface LeaderboardEntry {
  6→  rank: string;
  7→  name: string;
  8→  score: string;
  9→  accept_count: string;
 10→  acceptance_rate: string;
 11→  top_tag: string;
 12→  verified: string;
 13→}
 14→
 15→function decodeToonTable(
 16→  text: string,
 17→): { rows: LeaderboardEntry[] } | null {
 18→  const lines = text.trim().split("\n");
 19→  if (lines.length === 0) return null;
 20→
 21→  const firstLine = lines[0];
 22→  if (!firstLine) return null;
 23→  const headerMatch = firstLine.match(/^(\w+)\[(\d+)\]\{([^}]+)\}:$/);
 24→  if (!headerMatch || !headerMatch[3]) return null;
 25→
 26→  const fields = headerMatch[3].split(",");
 27→  const rows: LeaderboardEntry[] = [];
 28→
 29→  for (let i = 1; i < lines.length; i++) {
 30→    const line = lines[i];
 31→    if (!line) continue;
 32→    const values = line.trim().split(",");
 33→    const row: Record<string, string> = {};
 34→    for (let j = 0; j < fields.length; j++) {
 35→      const f = fields[j];
 36→      if (f) row[f] = values[j] || "";
 37→    }
 38→    rows.push(row as unknown as LeaderboardEntry);
 39→  }
 40→
 41→  return { rows };
 42→}
 43→
 44→async function getLeaderboard(): Promise<LeaderboardEntry[]> {
 45→  try {
 46→    const res = await fetch(`${API_BASE}/leaderboard?format=toon&limit=50`, {
 47→      next: { revalidate: 10 },
 48→    });
 49→    const text = await res.text();
 50→    const result = decodeToonTable(text);
 51→    return result?.rows || [];
 52→  } catch {
 53→    return [];
 54→  }
 55→}
